    	}
  	}

  	return params;
}

function() {  
  var params = {{URL_PARAMS}};
  var cSource,tmp_media;
  if (params.hasOwnProperty("utm_source")) {
    cSource = params.utm_source;     //유입 UTM에 utm_source 가 있으면 그대로 리턴
    return cSource;
  }

  //네이버광고 처리
  if (params.hasOwnProperty("n_media")) {
    cSource = "searchad.naver.com";
  }

  return cSource;
}

function() {  
  var params = {{URL_PARAMS}};
  var cContent, nRank, nKeyword;
  if (params.hasOwnProperty("utm_content")) {
    return params.utm_campaign;     //유입 UTM에 해당 값 있으면 그대로 리턴
    // return cContent;
  }

  //NAVER의 경우
  if (params.hasOwnProperty("n_rank")) {
    nRank = params.n_rank;
  }
  if (params.hasOwnProperty("n_keyword")) {
	nKeyword = decodeURIComponent(params.n_keyword); 
  }  

  //카카오의 경우
  if (params.hasOwnProperty("k_rank")) {
    nRank = params.k_rank;
   }
  if (params.hasOwnProperty("k_keyword")) {
	nKeyword = decodeURIComponent(params.k_keyword); 
  }  

  // content로 넘길 내용 순위 + 광고키워드
  if (nRank && nKeyword){
    cContent = '(순위/AD키워드) '+ nRank + '/' + nKeyword;  
  } else if (nRank){
    cContent = '(순위) '+ nRank;
  } else if (nKeyword){
    cContent = '(AD키워드) '+ nKeyword;
  }

  return cContent;
}

